export const mediaAssetKinds = ["note-image", "link-favicon"] as const;

export type MediaAssetKind = (typeof mediaAssetKinds)[number];

export type MediaAssetAccessRecord = {
  id: string;
  ownerId: string;
  kind: MediaAssetKind;
  storageKey: string;
  contentType: string;
  sizeBytes: number;
  note: {
    isPublished: boolean;
    markdown: string;
  } | null;
  link: {
    isPublished: boolean;
  } | null;
};

export type MediaAccessMode = "owner" | "public";

export function getMediaAssetPath(assetId: string) {
  return `/media/${assetId}`;
}

export function getMediaAssetIdsFromMarkdown(markdown: string) {
  const assetIds = new Set<string>();

  for (const match of markdown.matchAll(/\/media\/([a-zA-Z0-9-]+)/g)) {
    const assetId = match[1]?.trim();

    if (assetId) {
      assetIds.add(assetId);
    }
  }

  return [...assetIds];
}

export function isMediaAssetPubliclyVisible(asset: MediaAssetAccessRecord) {
  if (asset.kind === "note-image") {
    return Boolean(asset.note?.isPublished && asset.note.markdown.includes(getMediaAssetPath(asset.id)));
  }

  if (asset.kind === "link-favicon") {
    return Boolean(asset.link?.isPublished);
  }

  return false;
}

export function resolveMediaAssetAccess(asset: MediaAssetAccessRecord, viewerOwnerId: string | null): MediaAccessMode | null {
  if (viewerOwnerId && viewerOwnerId === asset.ownerId) {
    return "owner";
  }

  if (isMediaAssetPubliclyVisible(asset)) {
    return "public";
  }

  return null;
}

import "server-only";

import { prisma } from "@/lib/prisma";
import type { MediaAssetAccessRecord } from "@/features/media/types";

export const mediaRepo = {
  async findAccessRecordById(id: string): Promise<MediaAssetAccessRecord | null> {
    const asset = await prisma.mediaAsset.findUnique({
      where: {
        id
      },
      select: {
        id: true,
        ownerId: true,
        kind: true,
        storageKey: true,
        contentType: true,
        sizeBytes: true,
        note: {
          select: {
            isPublished: true,
            markdown: true
          }
        },
        link: {
          select: {
            isPublished: true
          }
        }
      }
    });

    if (!asset) {
      return null;
    }

    return {
      id: asset.id,
      ownerId: asset.ownerId,
      kind: asset.kind as MediaAssetAccessRecord["kind"],
      storageKey: asset.storageKey,
      contentType: asset.contentType,
      sizeBytes: asset.sizeBytes,
      note: asset.note,
      link: asset.link
    };
  },
  async createNoteImageAsset(data: {
    id: string;
    ownerId: string;
    noteId: string | null;
    storageKey: string;
    fileName: string;
    contentType: string;
    sizeBytes: number;
  }) {
    return prisma.mediaAsset.create({
      data: {
        id: data.id,
        ownerId: data.ownerId,
        noteId: data.noteId,
        kind: "note-image",
        storageKey: data.storageKey,
        fileName: data.fileName,
        contentType: data.contentType,
        sizeBytes: data.sizeBytes
      },
      select: {
        id: true
      }
    });
  },
  async attachOwnerNoteImagesToNote(ownerId: string, noteId: string, assetIds: string[]) {
    if (assetIds.length === 0) {
      return {
        count: 0
      };
    }

    return prisma.mediaAsset.updateMany({
      where: {
        id: {
          in: assetIds
        },
        kind: "note-image",
        ownerId,
        OR: [
          {
            noteId: null
          },
          {
            noteId
          }
        ]
      },
      data: {
        noteId
      }
    });
  }
};

